function showMessage(e,n,t=null){const s=document.getElementById("messageArea");s.innerHTML=`<div class='message ${n?"success":"error"}'>${e}</div>`,n&&t?setTimeout(()=>{let n=10;s.innerHTML=`\n        <div class='message success'>\n          ${e}<br><br>\n          Redirecting in <span id="countdown">${n}</span>s.\nAccess http://${t} manually if needed\n\n        </div>\n      `;const i=setInterval(()=>{n--,document.getElementById("countdown").textContent=n,n<=0&&(clearInterval(i),window.location.href="http://"+t)},1e3)},5e3):setTimeout(()=>{s.innerHTML=""},5e3)}function formatSize(e){return e<1024?e+" B":e<1048576?(e/1024).toFixed(1)+" KB":(e/1048576).toFixed(1)+" MB"}function formatSizeWithUnit(e){const n=["B","KB","MB","GB","TB"];let t,s=e,i=0;for(;s>=1024&&i<n.length-1;)s/=1024,i++;return t=0===i?s:s.toFixed(2),`${t} ${n[i]} `}